public class Main {
    public static void main(String[] args) {
        int age = 25;
        double price = 19.99;
        String name = "Ahmet";
        boolean isActive = true;
        char grade = 'A';

        System.out.println("Isim: " + name);
        System.out.println("Yas: " + age);
        System.out.println("Fiyat: " + price);
        System.out.println("Aktif mi: " + isActive);
        System.out.println("Not: " + grade);

        // Tip donusumu
        String ageText = String.valueOf(age);
        int parsedAge = Integer.parseInt("30");
        double parsedPrice = Double.parseDouble("9.5");

        System.out.println("\nYas metni: " + ageText);
        System.out.println("Donusturulen yas: " + parsedAge);
        System.out.println("Donusturulen fiyat: " + parsedPrice);

        // final ile sabit deger
        final double PI = 3.14159;
        System.out.println("\nPi sayisi: " + PI);

        // long, float ornekleri
        long bigNumber = 10000000000L;
        float smallDecimal = 3.14f;
        System.out.println("\nBuyuk sayi: " + bigNumber);
        System.out.println("Ondalik (float): " + smallDecimal);
    }
}
